    /// <summary>
    /// Kusto-backed Service Tree node lookup.
    /// </summary>
    public sealed class ServiceTreeKustoClient : IServiceTreeNodeLookup
    {
        private readonly ServiceTreeKustoOptions kustoOptions;
        private readonly ServiceTreeClientOptions authOptions;
        private readonly ILogger<ServiceTreeKustoClient> logger;
        private readonly TokenCredential? tokenCredential;
        private readonly string tokenScope;
        private readonly bool isConfigured;
        private readonly int maxBatchSize;
        private readonly int maxConcurrency = 4;

        /// <summary>
        /// Initializes a new instance of the <see cref="ServiceTreeKustoClient"/> class.
        /// </summary>
        /// <param name="kustoOptions">Kusto options.</param>
        /// <param name="authOptions">Auth options.</param>
        /// <param name="logger">Logger instance.</param>
        /// <param name="credentialFactory">Optional credential factory for cross-tenant support.</param>
        public ServiceTreeKustoClient(
            ServiceTreeKustoOptions kustoOptions,
            ServiceTreeClientOptions authOptions,
            ILogger<ServiceTreeKustoClient> logger,
            ICredentialFactory credentialFactory = null)
        {
            this.kustoOptions = kustoOptions ?? throw new ArgumentNullException(nameof(kustoOptions));
            this.authOptions = authOptions ?? throw new ArgumentNullException(nameof(authOptions));
            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));

            if (string.IsNullOrWhiteSpace(this.kustoOptions.ClusterUri)
                || string.IsNullOrWhiteSpace(this.kustoOptions.Database))
            {
                this.logger.LogWarning("ServiceTreeKustoClient: Kusto cluster or database is not configured.");
                this.isConfigured = false;
                return;
            }

            this.tokenScope = this.ResolveTokenScope(this.kustoOptions);
            if (string.IsNullOrWhiteSpace(this.tokenScope))
            {
                this.logger.LogWarning("ServiceTreeKustoClient: Token scope is not configured.");
                this.isConfigured = false;
                return;
            }

            this.tokenCredential = this.ResolveTokenCredential(credentialFactory, this.authOptions);
            if (this.tokenCredential == null)
            {
                this.logger.LogWarning("ServiceTreeKustoClient: No AAD credentials configured for Kusto.");
                this.isConfigured = false;
                return;
            }

            this.maxBatchSize = this.kustoOptions.MaxBatchSize <= 0 ? 200 : this.kustoOptions.MaxBatchSize;
            this.isConfigured = true;

            this.logger.LogInformation(
                "ServiceTreeKustoClient: Configured. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, TokenScope={TokenScope}.",
                this.kustoOptions.ClusterUri,
                this.kustoOptions.Database,
                this.kustoOptions.HierarchyTableName,
                this.tokenCredential.GetType().Name,
                this.tokenScope);
        }

        /// <inheritdoc/>
        public async Task<IReadOnlyDictionary<string, ServiceTreeNode>> GetHierarchyNodesByServiceIdsAsync(
            IEnumerable<string> serviceIds,
            CancellationToken cancellationToken)
        {
            var results = new ConcurrentDictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
            if (!this.isConfigured)
            {
                return results;
            }

            var uniqueIds = (serviceIds ?? Enumerable.Empty<string>())
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Select(id => id.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            if (uniqueIds.Count == 0)
            {
                return results;
            }

            var batches = this.SplitStringBatches(uniqueIds, this.maxBatchSize);
            using var semaphore = new SemaphoreSlim(this.maxConcurrency);
            var tasks = batches.Select(async batch =>
            {
                await semaphore.WaitAsync(cancellationToken);
                try
                {
                    var batchResults = await this.QueryHierarchyBatchAsync(batch, cancellationToken);
                    foreach (var pair in batchResults)
                    {
                        results[pair.Key] = pair.Value;
                    }
                }
                catch (OperationCanceledException)
                {
                    throw;
                }
                catch (Exception ex)
                {
                    this.logger.LogWarning(
                        ex,
                        "ServiceTreeKustoClient: Batch of {BatchCount} IDs failed; continuing with remaining batches.",
                        batch.Count);
                }
                finally
                {
                    semaphore.Release();
                }
            }).ToList();

            await Task.WhenAll(tasks);
            return results;
        }

